module top_module(
  input clk,
  input reset,
  input enable,
  output [3:0] count
);reg [3:0] obf_count_reg;

  always @(posedge clk) begin
    if (reset) begin
      obf_count_reg <= 4'b0;
    end
    else if (enable) begin
      obf_count_reg <= obf_count_reg + 1;
    end
  end

  assign count = obf_count_reg;

endmodule
